/**
 * src/adapters/rexel.test.ts
 *
 * Unit tests for RexelAdapter.
 * All HTTP calls intercepted by MSW.
 */

import { describe, it, expect, beforeAll, afterAll, afterEach, vi } from 'vitest';
import { http, HttpResponse } from 'msw';
import { setupServer } from 'msw/node';
import axios from 'axios';
import { RexelAdapter } from './rexel';
import { FetchError } from '@/types/error';

const SKU = '70569480';
const API_URL = 'https://eu.dif.rexel.com/web/api/v3/product/priceandavailability';
const TOKEN = 'test-bearer-token';

function makeResponse(overrides?: {
  sku?: string;
  unitPrice?: number;
  availableQty?: number;
  noPrices?: boolean;
}) {
  const o = { sku: SKU, unitPrice: 21.048, availableQty: 2, noPrices: false, ...overrides };
  return {
    lines: [
      {
        sku: o.sku,
        prices: o.noPrices ? [] : [
          { price: { amount: o.unitPrice, currency: 'EUR' }, priceLabel: 'UNIT_LIST_PRICE' },
          { price: { amount: 21.05, currency: 'EUR' }, priceLabel: 'LINE_TOTAL_PRICE_NOVAT' },
          { price: { amount: 33.904, currency: 'EUR' }, priceLabel: 'GROSS_LIST_PRICE' },
        ],
        availabilities: [
          { type: 'DELIVERY_BRANCH_AVAILABILITY', quantity: { available: o.availableQty } },
        ],
      },
    ],
  };
}

const server = setupServer();
beforeAll(() => server.listen({ onUnhandledRequest: 'error' }));
afterEach(() => server.resetHandlers());
afterAll(() => server.close());

function mockApi(body: object, status = 200) {
  server.use(http.post(API_URL, () =>
    status === 200
      ? HttpResponse.json(body, { status: 200 })
      : new HttpResponse(null, { status })
  ));
}

describe('RexelAdapter', () => {
  let adapter: RexelAdapter;
  beforeAll(() => { adapter = new RexelAdapter(TOKEN); });

  it('has correct supplierId', () => {
    expect(adapter.supplierId).toBe('rexel');
  });

  it('throws AUTH_ERROR when no token provided', async () => {
    const empty = new RexelAdapter('');
    await expect(empty.getPrice(SKU)).rejects.toMatchObject({ code: 'AUTH_ERROR' });
  });

  describe('getPrice — happy path', () => {
    it('parses UNIT_LIST_PRICE and in-stock availability', async () => {
      mockApi(makeResponse());
      const price = await adapter.getPrice(SKU);
      expect(price.prix_ht).toBe(21.048);
      expect(price.stock).toBe(1);
      expect(price.unite).toBe('pièce');
      expect(price.fetchedAt).toMatch(/^\d{4}-\d{2}-\d{2}T/);
    });

    it('returns stock=0 when all delivery availabilities are 0', async () => {
      mockApi(makeResponse({ availableQty: 0 }));
      const price = await adapter.getPrice(SKU);
      expect(price.stock).toBe(0);
    });

    it('falls back to LINE_TOTAL_PRICE_NOVAT when UNIT_LIST_PRICE absent', async () => {
      const body = makeResponse();
      body.lines[0].prices = body.lines[0].prices.filter(
        (p) => p.priceLabel !== 'UNIT_LIST_PRICE'
      );
      mockApi(body);
      const price = await adapter.getPrice(SKU);
      expect(price.prix_ht).toBe(21.05);
    });
  });

  describe('getPrice — error cases', () => {
    it('throws AUTH_ERROR on HTTP 401', async () => {
      mockApi({}, 401);
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'AUTH_ERROR', retryable: false });
    });

    it('throws AUTH_ERROR on HTTP 403', async () => {
      mockApi({}, 403);
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'AUTH_ERROR' });
    });

    it('throws RATE_LIMIT on HTTP 429', async () => {
      mockApi({}, 429);
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'RATE_LIMIT', retryable: true });
    });

    it('throws NOT_FOUND on HTTP 404', async () => {
      mockApi({}, 404);
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'NOT_FOUND' });
    });

    it('throws NETWORK_ERROR on HTTP 503', async () => {
      mockApi({}, 503);
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'NETWORK_ERROR', retryable: true });
    });

    it('throws NETWORK_ERROR on connection failure', async () => {
      server.use(http.post(API_URL, () => HttpResponse.error()));
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'NETWORK_ERROR' });
    });

    it('throws NETWORK_ERROR on non-axios error', async () => {
      const spy = vi.spyOn(axios, 'post').mockRejectedValueOnce(new TypeError('plain error'));
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'NETWORK_ERROR' });
      spy.mockRestore();
    });

    it('throws NOT_FOUND when lines array is empty', async () => {
      mockApi({ lines: [] });
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'NOT_FOUND' });
    });

    it('throws PARSE_ERROR when no prices in line', async () => {
      mockApi(makeResponse({ noPrices: true }));
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'PARSE_ERROR' });
    });
  });
});

/**
 * src/adapters/rexel.test.ts
 *
 * Unit tests for RexelAdapter.
 * All HTTP calls intercepted by MSW.
 */

import { describe, it, expect, beforeAll, afterAll, afterEach, vi } from 'vitest';
import { http, HttpResponse } from 'msw';
import { setupServer } from 'msw/node';
import axios from 'axios';
import { RexelAdapter, decodeRexelToken, extractAccountId, extractWebshopId, extractApiKey } from './rexel';
import { FetchError } from '@/types/error';

const SKU = '70569480';
const API_URL = 'https://eu.dif.rexel.com/web/api/v3/product/priceandavailability';

// Build a minimal valid JWT with an accountNumber, webshopId and api_key embedded
function makeJwt(accountNumber: string, webshopId = 'FRW', apiKey = 'test-api-key'): string {
  const payload = Buffer.from(
    JSON.stringify({
      ERPCustomerID: { accountNumber },
      WebshopID: { webshopId },
      api_key: apiKey,
      exp: 9999999999,
    })
  ).toString('base64url');
  return `header.${payload}.signature`;
}

const ACCOUNT_ID = '6440598';
const TOKEN = makeJwt(ACCOUNT_ID);
const BRANCH_ID = '4413';
const CREDS = { token: TOKEN, branchId: BRANCH_ID };

function makeResponse(overrides?: {
  sku?: string;
  unitPrice?: number;
  availableQty?: number;
  noPrices?: boolean;
}) {
  const o = { sku: SKU, unitPrice: 21.048, availableQty: 2, noPrices: false, ...overrides };
  return {
    lines: [
      {
        sku: o.sku,
        prices: o.noPrices ? [] : [
          { price: { amount: o.unitPrice, currency: 'EUR' }, priceLabel: 'UNIT_LIST_PRICE' },
          { price: { amount: 21.05, currency: 'EUR' }, priceLabel: 'LINE_TOTAL_PRICE_NOVAT' },
          { price: { amount: 33.904, currency: 'EUR' }, priceLabel: 'GROSS_LIST_PRICE' },
        ],
        availabilities: [
          { type: 'DELIVERY_BRANCH_AVAILABILITY', quantity: { available: o.availableQty } },
        ],
      },
    ],
  };
}

const server = setupServer();
beforeAll(() => server.listen({ onUnhandledRequest: 'error' }));
afterEach(() => server.resetHandlers());
afterAll(() => server.close());

function mockApi(body: object, status = 200) {
  server.use(http.post(API_URL, () =>
    status === 200
      ? HttpResponse.json(body, { status: 200 })
      : new HttpResponse(null, { status })
  ));
}

describe('RexelAdapter', () => {
  let adapter: RexelAdapter;
  beforeAll(() => { adapter = new RexelAdapter(CREDS); });

  // ── JWT helpers ─────────────────────────────────────────────────────────────

  describe('decodeRexelToken', () => {
    it('extracts accountNumber from a valid JWT', () => {
      const decoded = decodeRexelToken(TOKEN);
      expect(decoded.ERPCustomerID?.accountNumber).toBe(ACCOUNT_ID);
    });

    it('returns empty object for a garbage token', () => {
      expect(decodeRexelToken('not.a.jwt')).toEqual({});
    });

    it('returns empty object for an empty string', () => {
      expect(decodeRexelToken('')).toEqual({});
    });
  });

  describe('extractAccountId', () => {
    it('returns the accountNumber from a valid JWT', () => {
      expect(extractAccountId(TOKEN)).toBe(ACCOUNT_ID);
    });

    it('returns empty string when token has no ERPCustomerID', () => {
      const bare = `header.${Buffer.from('{}').toString('base64url')}.sig`;
      expect(extractAccountId(bare)).toBe('');
    });
  });

  describe('extractWebshopId', () => {
    it('returns the webshopId from a valid JWT', () => {
      expect(extractWebshopId(TOKEN)).toBe('FRW');
    });

    it('returns empty string when token has no WebshopID', () => {
      const bare = `header.${Buffer.from('{}').toString('base64url')}.sig`;
      expect(extractWebshopId(bare)).toBe('');
    });
  });

  describe('extractApiKey', () => {
    it('returns the api_key from a valid JWT', () => {
      expect(extractApiKey(TOKEN)).toBe('test-api-key');
    });

    it('returns empty string when token has no api_key', () => {
      const bare = `header.${Buffer.from('{}').toString('base64url')}.sig`;
      expect(extractApiKey(bare)).toBe('');
    });
  });

  it('has correct supplierId', () => {
    expect(adapter.supplierId).toBe('rexel');
  });

  it('throws AUTH_ERROR when no token provided', async () => {
    const empty = new RexelAdapter({ token: '', branchId: BRANCH_ID });
    await expect(empty.getPrice(SKU)).rejects.toMatchObject({ code: 'AUTH_ERROR' });
  });

  it('throws AUTH_ERROR when token has no accountId', async () => {
    const noAccount = `header.${Buffer.from('{"exp":9999}').toString('base64url')}.sig`;
    const a = new RexelAdapter({ token: noAccount, branchId: BRANCH_ID });
    await expect(a.getPrice(SKU)).rejects.toMatchObject({ code: 'AUTH_ERROR' });
  });

  it('throws AUTH_ERROR when branchId is missing', async () => {
    const a = new RexelAdapter({ token: TOKEN, branchId: '' });
    await expect(a.getPrice(SKU)).rejects.toMatchObject({ code: 'AUTH_ERROR' });
  });

  describe('getPrice — happy path', () => {
    it('parses UNIT_LIST_PRICE and in-stock availability', async () => {
      mockApi(makeResponse());
      const price = await adapter.getPrice(SKU);
      expect(price.prix_ht).toBe(21.048);
      expect(price.stock).toBe(1);
      expect(price.unite).toBe('pièce');
      expect(price.fetchedAt).toMatch(/^\d{4}-\d{2}-\d{2}T/);
    });

    it('returns stock=0 when all delivery availabilities are 0', async () => {
      mockApi(makeResponse({ availableQty: 0 }));
      const price = await adapter.getPrice(SKU);
      expect(price.stock).toBe(0);
    });

    it('falls back to LINE_TOTAL_PRICE_NOVAT when UNIT_LIST_PRICE absent', async () => {
      const body = makeResponse();
      body.lines[0].prices = body.lines[0].prices.filter(
        (p) => p.priceLabel !== 'UNIT_LIST_PRICE'
      );
      mockApi(body);
      const price = await adapter.getPrice(SKU);
      expect(price.prix_ht).toBe(21.05);
    });
  });

  describe('getPrice — error cases', () => {
    it('throws AUTH_ERROR on HTTP 401', async () => {
      mockApi({}, 401);
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'AUTH_ERROR', retryable: false });
    });

    it('throws AUTH_ERROR on HTTP 403', async () => {
      mockApi({}, 403);
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'AUTH_ERROR' });
    });

    it('throws RATE_LIMIT on HTTP 429', async () => {
      mockApi({}, 429);
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'RATE_LIMIT', retryable: true });
    });

    it('throws NOT_FOUND on HTTP 404', async () => {
      mockApi({}, 404);
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'NOT_FOUND' });
    });

    it('throws NETWORK_ERROR on HTTP 503', async () => {
      mockApi({}, 503);
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'NETWORK_ERROR', retryable: true });
    });

    it('throws NETWORK_ERROR on connection failure', async () => {
      server.use(http.post(API_URL, () => HttpResponse.error()));
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'NETWORK_ERROR' });
    });

    it('throws NETWORK_ERROR on non-axios error', async () => {
      const spy = vi.spyOn(axios, 'post').mockRejectedValueOnce(new TypeError('plain error'));
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'NETWORK_ERROR' });
      spy.mockRestore();
    });

    it('throws NOT_FOUND when lines array is empty', async () => {
      mockApi({ lines: [] });
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'NOT_FOUND' });
    });

    it('throws PARSE_ERROR when no prices in line', async () => {
      mockApi(makeResponse({ noPrices: true }));
      await expect(adapter.getPrice(SKU)).rejects.toMatchObject({ code: 'PARSE_ERROR' });
    });
  });
});

/**
 * src/adapters/rexel.ts
 *
 * Rexel adapter — calls the internal SAP Commerce Cloud price API:
 *   POST https://eu.dif.rexel.com/web/api/v3/product/priceandavailability
 *
 * Requires a Bearer token obtained after the user logs in to rexel.fr.
  return decodeRexelToken(jwt).api_key ?? '';
}

// ── Credentials ───────────────────────────────────────────────────────────────

/**
 * Everything needed to call the price API.
 * branchId is the user's local Rexel agency code (e.g. "4413").
 * It is NOT in the JWT — the user must supply it (shown in the login modal).
 */
export interface RexelCredentials {
  token: string;
  branchId: string;
}

// ── Response shape (minimal) ──────────────────────────────────────────────────

interface RexelPrice {
  price: { amount: number; currency: string };
  priceLabel: string;
}

interface RexelAvailability {
  type: string;
  quantity: { available: number };
}

interface RexelLine {
  sku: string;
  prices: RexelPrice[];
  availabilities: RexelAvailability[];
}

interface RexelResponse {
  lines: RexelLine[];
}

// ── Adapter ───────────────────────────────────────────────────────────────────

export class RexelAdapter extends SupplierAdapter {
  readonly supplierId = 'rexel';
  private readonly token: string;
  private readonly accountId: string;
  private readonly branchId: string;

  constructor(credentials: RexelCredentials) {
    super();
    this.token = credentials.token;
    this.accountId = extractAccountId(credentials.token);
    this.branchId = credentials.branchId;
  }

  async getPrice(reference: string): Promise<SupplierPrice> {
    if (!this.token) {
      throw new FetchError({
        code: 'AUTH_ERROR',
        supplierId: this.supplierId,
        message: 'Token Rexel manquant — veuillez vous connecter.',
        retryable: false,
      });
    }
    if (!this.accountId) {
      throw new FetchError({
        code: 'AUTH_ERROR',
        supplierId: this.supplierId,
        message: 'Token Rexel invalide : accountId introuvable dans le JWT.',
        retryable: false,
      });
    }
    if (!this.branchId) {
      throw new FetchError({
        code: 'AUTH_ERROR',
        supplierId: this.supplierId,
        message: 'Code agence Rexel manquant — veuillez le renseigner dans la connexion.',
        retryable: false,
      });
    }

    let data: RexelResponse;
    try {
      const response = await axios.post<RexelResponse>(
        API_URL,
        // Body shape matching the real browser request to eu.dif.rexel.com
        {
          accountId: this.accountId,
          branchId: this.branchId,
          pickupOptions: { branchCode: this.branchId },
          stockReturnedOptions: {
            includeDCStock: true,
  constructor(token: string) {
            includeDelay: true,
          },
    this.token = token;
          lines: [{ sku: reference, quantity: { number: 1 } }],
        },
        {
          headers: {
            Authorization: `Bearer ${this.token}`,
            'Content-Type': 'application/json',
            'Content-Language': 'fr',
            Accept: 'application/json, text/plain, */*',
            'Accept-Language': 'fr,fr-FR;q=0.9,en-US;q=0.8,en;q=0.7',
            'x-banner': BANNER,
            statusCode: status,
            retryable: false,
          });
        }
        if (status === 400) {
          // Surface the response body so it's visible in the UI for debugging
          const detail = JSON.stringify(err.response?.data ?? {});
          throw new FetchError({
            code: 'PARSE_ERROR',
            supplierId: this.supplierId,
            message: `Requête invalide (400) — ${detail}`,
            statusCode: 400,
            retryable: false,
          });
        }
        if (status === 429) {
          throw new FetchError({
            code: 'RATE_LIMIT',
          banner: BANNER,
          webshopId: 'FRW',
          lines: [
            {
              sku: reference,
              quantity: 1,
              unit: 'PCE',
              priceCondition: { id: '0' },
            },
          ],
          supplierId: this.supplierId,
          message: err.message,
          statusCode: status,
          retryable: true,
        });
      }
      throw new FetchError({
        code: 'NETWORK_ERROR',
        supplierId: this.supplierId,
        message: String(err),
        retryable: true,
      });
    }

    return this.parseLine(data, reference);
  }

  parseLine(data: RexelResponse, reference: string): SupplierPrice {
    const line = data.lines?.[0];
    if (!line) {
      throw new FetchError({
        code: 'NOT_FOUND',
        supplierId: this.supplierId,
        message: `Aucune ligne de prix dans la réponse pour ${reference}.`,
        retryable: false,
      });
    }

    // Prefer UNIT_LIST_PRICE (net after discount), fallback to LINE_TOTAL_PRICE_NOVAT
    const unitPrice =
      line.prices.find((p) => p.priceLabel === 'UNIT_LIST_PRICE') ??
      line.prices.find((p) => p.priceLabel === 'LINE_TOTAL_PRICE_NOVAT');

    if (!unitPrice || typeof unitPrice.price.amount !== 'number') {
      throw new FetchError({
        code: 'PARSE_ERROR',
        supplierId: this.supplierId,
        message: `Prix introuvable dans la réponse Rexel pour ${reference}.`,
        retryable: false,
      });
    }

    // Stock: in stock if any delivery availability has available > 0
    const hasStock = line.availabilities?.some(
      (a) =>
        a.type === 'DELIVERY_BRANCH_AVAILABILITY' && (a.quantity?.available ?? 0) > 0
      (a) => a.type === 'DELIVERY_BRANCH_AVAILABILITY' && (a.quantity?.available ?? 0) > 0
    ) ?? false;

    return {
      prix_ht: unitPrice.price.amount,
      stock: hasStock ? 1 : 0,
      unite: 'pièce',
      fetchedAt: new Date().toISOString(),
    };
  }
}

/**
 * src/adapters/rexel.ts
 */

import axios from 'axios';
import { SupplierAdapter } from './base';
import { FetchError } from '@/types/error';
import type { SupplierPrice } from '@/types/price';

const API_URL = 'https://eu.dif.rexel.com/web/api/v3/product/priceandavailability';
const BANNER = 'frx';

// ── JWT helpers ───────────────────────────────────────────────────────────────

interface RexelJwtPayload {
  ERPCustomerID?: { accountNumber?: string };
  api_key?: string;
  WebshopID?: { webshopId?: string };
  exp?: number;
}

/** Decode the middle (payload) segment of a JWT without verifying the signature. */
export function decodeRexelToken(jwt: string): RexelJwtPayload {
  try {
    const seg = jwt.split('.')[1] ?? '';
    const pad = (4 - (seg.length % 4)) % 4;
    const b64 = (seg + '='.repeat(pad)).replace(/-/g, '+').replace(/_/g, '/');
    // Works in both browser (atob) and Node (Buffer)
    const json = typeof Buffer !== 'undefined'
      ? Buffer.from(b64, 'base64').toString('utf-8')
      : atob(b64);
    return JSON.parse(json) as RexelJwtPayload;
  } catch {
    return {};
  }
}

/** Extract the account number required by the price API. */
export function extractAccountId(jwt: string): string {
  return decodeRexelToken(jwt).ERPCustomerID?.accountNumber ?? '';
}

/** Extract the webshop ID from the JWT (e.g. "FRW"). */
export function extractWebshopId(jwt: string): string {
  return decodeRexelToken(jwt).WebshopID?.webshopId ?? '';
}

/** Extract the api_key from the JWT. */
export function extractApiKey(jwt: string): string {
  return decodeRexelToken(jwt).api_key ?? '';
}

// ── Credentials ───────────────────────────────────────────────────────────────

/**
 * Everything needed to call the price API.
 * branchId, zipcode and city are the user's local agency info, NOT in the JWT.
 */
export interface RexelCredentials {
  token: string;
  branchId: string;
  zipcode: string;
  city: string;
}

// ── Response shape (minimal) ──────────────────────────────────────────────────

interface RexelPrice {
  price: { amount: number; currency: string };
  priceLabel: string;
}

interface RexelAvailability {
  type: string;
  quantity: { available: number };
}

interface RexelLine {
  sku: string;
  prices: RexelPrice[];
  availabilities: RexelAvailability[];
}

interface RexelResponse {
  lines: RexelLine[];
}

// ── Adapter ───────────────────────────────────────────────────────────────────

export class RexelAdapter extends SupplierAdapter {
  readonly supplierId = 'rexel';
  private readonly token: string;
  private readonly accountId: string;
  private readonly branchId: string;
  private readonly zipcode: string;
  private readonly city: string;

  constructor(credentials: RexelCredentials) {
    super();
    this.token = credentials.token;
    this.accountId = extractAccountId(credentials.token);
    this.branchId = credentials.branchId;
    this.zipcode = credentials.zipcode;
    this.city = credentials.city;
  }

  async getPrice(reference: string): Promise<SupplierPrice> {
    if (!this.token) {
      throw new FetchError({
        code: 'AUTH_ERROR',
        supplierId: this.supplierId,
        message: 'Token Rexel manquant — veuillez vous connecter.',
        retryable: false,
      });
    }
    if (!this.accountId) {
      throw new FetchError({
        code: 'AUTH_ERROR',
        supplierId: this.supplierId,
        message: 'Token Rexel invalide : accountId introuvable dans le JWT.',
        retryable: false,
      });
    }
    if (!this.branchId) {
      throw new FetchError({
        code: 'AUTH_ERROR',
        supplierId: this.supplierId,
        message: 'Code agence Rexel manquant — veuillez le renseigner dans la connexion.',
        retryable: false,
      });
    }

    let data: RexelResponse;
    try {
      const response = await axios.post<RexelResponse>(
        API_URL,
        {
          accountId: this.accountId,
          branchId: this.branchId,
          pickupOptions: { branchCode: this.branchId },
          deliveryOptions: {
            branchCode: this.branchId,
            location: { country: 'FR', zipcode: this.zipcode, city: this.city },
          },
          stockReturnedOptions: {
            includeDCStock: true,
            includeBranchStock: true,
            includeDelay: true,
          },
          includeLeasePrice: true,
          // quantity MUST be an object {number: N} — primitive triggers "Failed to read request"
          lines: [{ sku: reference, quantity: { number: 1 } }],
        },
        {
          headers: {
            Authorization: `Bearer ${this.token}`,
            'Content-Type': 'application/json',
            'Content-Language': 'fr',
            Accept: 'application/json, text/plain, */*',
            'Accept-Language': 'fr,fr-FR;q=0.9,en-US;q=0.8,en;q=0.7',
            'x-banner': BANNER,
            Origin: 'https://www.rexel.fr',
            Referer: 'https://www.rexel.fr/',
          },
          timeout: 15_000,
        }
      );
      data = response.data;
    } catch (err) {
      if (axios.isAxiosError(err)) {
        const status = err.response?.status;
        if (status === 401 || status === 403) {
          throw new FetchError({
            code: 'AUTH_ERROR',
            supplierId: this.supplierId,
            message: 'Token Rexel expiré ou invalide — veuillez vous reconnecter.',
            statusCode: status,
            retryable: false,
          });
        }
        if (status === 400) {
          const detail = JSON.stringify(err.response?.data ?? {});
          throw new FetchError({
            code: 'PARSE_ERROR',
            supplierId: this.supplierId,
            message: `Requête invalide (400) — ${detail}`,
            statusCode: 400,
            retryable: false,
          });
        }
        if (status === 429) {
          throw new FetchError({
            code: 'RATE_LIMIT',
            supplierId: this.supplierId,
            message: 'Rate limité par Rexel.',
            statusCode: 429,
            retryable: true,
          });
        }
        if (status === 404) {
          throw new FetchError({
            code: 'NOT_FOUND',
            supplierId: this.supplierId,
            message: `Référence ${reference} introuvable chez Rexel.`,
            statusCode: 404,
            retryable: false,
          });
        }
        throw new FetchError({
          code: 'NETWORK_ERROR',
          supplierId: this.supplierId,
          message: err.message,
          statusCode: status,
          retryable: true,
        });
      }
      throw new FetchError({
        code: 'NETWORK_ERROR',
        supplierId: this.supplierId,
        message: String(err),
        retryable: true,
      });
    }

    return this.parseLine(data, reference);
  }

  parseLine(data: RexelResponse, reference: string): SupplierPrice {
    const line = data.lines?.[0];
    if (!line) {
      throw new FetchError({
        code: 'NOT_FOUND',
        supplierId: this.supplierId,
        message: `Aucune ligne de prix dans la réponse pour ${reference}.`,
        retryable: false,
      });
    }

    // Prefer UNIT_LIST_PRICE (net after discount), fallback to LINE_TOTAL_PRICE_NOVAT
    const unitPrice =
      line.prices.find((p) => p.priceLabel === 'UNIT_LIST_PRICE') ??
      line.prices.find((p) => p.priceLabel === 'LINE_TOTAL_PRICE_NOVAT');

    if (!unitPrice || typeof unitPrice.price.amount !== 'number') {
      throw new FetchError({
        code: 'PARSE_ERROR',
        supplierId: this.supplierId,
        message: `Prix introuvable dans la réponse Rexel pour ${reference}.`,
        retryable: false,
      });
    }

    const hasStock = line.availabilities?.some(
      (a) => a.type === 'DELIVERY_BRANCH_AVAILABILITY' && (a.quantity?.available ?? 0) > 0
    ) ?? false;

    return {
      prix_ht: unitPrice.price.amount,
      stock: hasStock ? 1 : 0,
      unite: 'pièce',
      fetchedAt: new Date().toISOString(),
    };
  }
}

/**
 * src/components/RexelLoginModal.tsx
 */
import React, { useState, useCallback, useEffect } from 'react';
import { extractAccountId } from '@/adapters/rexel';
interface RexelLoginModalProps {
  currentToken: string;
  onSave: (token: string) => void;
  onClear: () => void;
  onClose: () => void;
}
export function RexelLoginModal({ currentToken, onSave, onClear, onClose }: RexelLoginModalProps): React.ReactElement {
  const [draft, setDraft] = useState(currentToken);
  const [showToken, setShowToken] = useState(false);
  useEffect(() => {
    const h = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
    window.addEventListener('keydown', h);
    return () => window.removeEventListener('keydown', h);
  }, [onClose]);
  const handleSave = useCallback(() => {
    const clean = draft.trim().replace(/^Bearer\s+/i, '');
    if (!clean) return;
    onSave(clean);
    onClose();
  }, [draft, onSave, onClose]);
  const hasToken = currentToken.length > 0;
  const draftClean = draft.trim().replace(/^Bearer\s+/i, '');
  const draftAccountId = draftClean ? extractAccountId(draftClean) : '';
  const draftValid = draftAccountId.length > 0;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm"
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg mx-4 overflow-hidden">
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <div className="flex items-center gap-2">
            <span className="text-lg"></span>
            <h2 className="text-base font-semibold text-gray-900">Connexion Rexel</h2>
            {hasToken && (
              <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-700">
                ✓ Connecté
              </span>
            )}
          </div>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 text-xl leading-none">x</button>
        </div>
        <div className="px-6 pt-5 pb-0">
          <div className="bg-blue-50 border border-blue-100 rounded-lg px-4 py-3 text-xs text-blue-700 space-y-1">
            <p className="font-semibold text-blue-800 text-sm">Comment obtenir votre token Rexel :</p>
            <ol className="list-decimal list-inside space-y-0.5">
              <li>Connectez-vous sur rexel.fr</li>
              <li>Ouvrez DevTools (F12) onglet Reseau et filtrez priceandavailability</li>
              <li>Naviguez vers une fiche produit pour declencher la requete</li>
              <li>Clic droit sur la requete - Copier en tant que fetch</li>
              <li>Copiez la valeur apres Bearer dans le header Authorization</li>
            </ol>
          </div>
        </div>
        <div className="px-6 py-4 space-y-2">
          <label className="block text-xs font-medium text-gray-700">
            Token Bearer (sans le prefixe Bearer)
          </label>
          <div className="relative">
            <textarea
              value={draft}
              onChange={(e) => setDraft(e.target.value)}
              rows={3}
              className="w-full border border-gray-200 rounded-lg px-3 py-2 text-xs font-mono focus:outline-none focus:ring-2 focus:ring-blue-400 resize-none"
              placeholder="eyJhbGciOiJSUzI1NiJ9..."
              style={{ filter: showToken ? 'none' : 'blur(3px)' }}
            />
            <button type="button" onClick={() => setShowToken((v) => !v)}
              className="absolute top-2 right-2 text-xs text-gray-400 hover:text-gray-600 bg-white px-1.5 py-0.5 rounded border border-gray-200">
              {showToken ? 'Masquer' : 'Afficher'}
            </button>
          </div>
          {draftClean && (
            draftValid ? (
              <p className="text-xs text-green-600 bg-green-50 border border-green-200 rounded px-2 py-1">
                Token valide - compte {draftAccountId} detecte
              </p>
            ) : (
              <p className="text-xs text-red-600 bg-red-50 border border-red-200 rounded px-2 py-1">
                Token invalide - aucun accountId dans le JWT. Verifiez que vous etes connecte sur rexel.fr.
              </p>
            )
          )}
          <p className="text-xs text-gray-400">Valide environ 30 jours. Stocke uniquement dans votre navigateur (localStorage).</p>
        </div>
        <div className="flex items-center justify-between px-6 py-4 border-t border-gray-100 bg-gray-50/50">
          {hasToken
            ? <button onClick={() => { onClear(); onClose(); }} className="text-sm text-red-500 hover:bg-red-50 px-4 py-2 rounded-lg transition-colors">Se deconnecter</button>
            : <div />}
          <div className="flex gap-2">
            <button onClick={onClose} className="px-4 py-2 text-sm text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">Annuler</button>
            <button onClick={handleSave} disabled={!draftValid}
              className="px-4 py-2 text-sm font-medium bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors disabled:opacity-40 disabled:cursor-not-allowed">
              Enregistrer
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * src/components/RexelLoginModal.tsx
 */
import React, { useState, useCallback, useEffect } from 'react';
import { extractAccountId, type RexelCredentials } from '@/adapters/rexel';

interface RexelLoginModalProps {
  currentToken: string;
  currentBranchId: string;
  onSave: (credentials: RexelCredentials) => void;
  onClear: () => void;
  onClose: () => void;
}

export function RexelLoginModal({ currentToken, currentBranchId, onSave, onClear, onClose }: RexelLoginModalProps): React.ReactElement {
  const [draft, setDraft] = useState(currentToken);
  const [draftBranch, setDraftBranch] = useState(currentBranchId);
  const [showToken, setShowToken] = useState(false);

  useEffect(() => {
    const h = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
    window.addEventListener('keydown', h);
    return () => window.removeEventListener('keydown', h);
  }, [onClose]);

  const handleSave = useCallback(() => {
    const cleanToken = draft.trim().replace(/^Bearer\s+/i, '');
    const cleanBranch = draftBranch.trim();
    if (!cleanToken || !cleanBranch) return;
    onSave({ token: cleanToken, branchId: cleanBranch });
    onClose();
  }, [draft, draftBranch, onSave, onClose]);

  const hasToken = currentToken.length > 0;
  const draftClean = draft.trim().replace(/^Bearer\s+/i, '');
  const draftAccountId = draftClean ? extractAccountId(draftClean) : '';
  const draftBranchClean = draftBranch.trim();
  const draftValid = draftAccountId.length > 0 && draftBranchClean.length > 0;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm"
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg mx-4 overflow-hidden">
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <div className="flex items-center gap-2">
            <span className="text-lg"></span>
            <h2 className="text-base font-semibold text-gray-900">Connexion Rexel</h2>
            {hasToken && (
              <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-700">
                ✓ Connecté
              </span>
            )}
          </div>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 text-xl leading-none">x</button>
        </div>

        <div className="px-6 pt-5 pb-0">
          <div className="bg-blue-50 border border-blue-100 rounded-lg px-4 py-3 text-xs text-blue-700 space-y-1">
            <p className="font-semibold text-blue-800 text-sm">Comment obtenir votre token et code agence :</p>
            <ol className="list-decimal list-inside space-y-0.5">
              <li>Connectez-vous sur rexel.fr</li>
              <li>Ouvrez DevTools (F12) onglet Réseau, filtrez <strong>priceandavailability</strong></li>
              <li>Naviguez vers une fiche produit pour déclencher la requête</li>
              <li>Clic droit sur la requête → Copier en tant que fetch</li>
              <li>Dans le <strong>body</strong>, relevez <strong>branchId</strong> (ex: "4413")</li>
              <li>Dans les headers, copiez la valeur après <strong>Bearer</strong></li>
            </ol>
          </div>
        </div>

        <div className="px-6 py-4 space-y-4">
          {/* Token */}
          <div className="space-y-2">
            <label className="block text-xs font-medium text-gray-700">
              Token Bearer (sans le préfixe "Bearer ")
            </label>
            <div className="relative">
              <textarea
                value={draft}
                onChange={(e) => setDraft(e.target.value)}
                rows={3}
                className="w-full border border-gray-200 rounded-lg px-3 py-2 text-xs font-mono focus:outline-none focus:ring-2 focus:ring-blue-400 resize-none"
                placeholder="eyJhbGciOiJSUzI1NiJ9..."
                style={{ filter: showToken ? 'none' : 'blur(3px)' }}
              />
              <button type="button" onClick={() => setShowToken((v) => !v)}
                className="absolute top-2 right-2 text-xs text-gray-400 hover:text-gray-600 bg-white px-1.5 py-0.5 rounded border border-gray-200">
                {showToken ? 'Masquer' : 'Afficher'}
              </button>
            </div>
            {draftClean && (
              draftAccountId ? (
                <p className="text-xs text-green-600 bg-green-50 border border-green-200 rounded px-2 py-1">
                  Token valide — compte {draftAccountId} détecté
                </p>
              ) : (
                <p className="text-xs text-red-600 bg-red-50 border border-red-200 rounded px-2 py-1">
                  Token invalide — aucun accountId dans le JWT. Vérifiez que vous êtes connecté sur rexel.fr.
                </p>
              )
            )}
          </div>

          {/* Branch ID */}
          <div className="space-y-2">
            <label className="block text-xs font-medium text-gray-700">
              Code agence Rexel <span className="text-gray-400">(champ <code className="bg-gray-100 px-1 rounded">branchId</code> dans le body de la requête)</span>
            </label>
            <input
              type="text"
              value={draftBranch}
              onChange={(e) => setDraftBranch(e.target.value)}
              className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm font-mono focus:outline-none focus:ring-2 focus:ring-blue-400"
              placeholder="4413"
              maxLength={10}
            />
            {draftBranchClean.length > 0 && (
              <p className="text-xs text-green-600 bg-green-50 border border-green-200 rounded px-2 py-1">
                Agence {draftBranchClean} configurée
              </p>
            )}
          </div>

          <p className="text-xs text-gray-400">Token valide environ 30 jours. Stocké uniquement dans votre navigateur (localStorage).</p>
        </div>

        <div className="flex items-center justify-between px-6 py-4 border-t border-gray-100 bg-gray-50/50">
          {hasToken
            ? <button onClick={() => { onClear(); onClose(); }} className="text-sm text-red-500 hover:bg-red-50 px-4 py-2 rounded-lg transition-colors">Se déconnecter</button>
            : <div />}
          <div className="flex gap-2">
            <button onClick={onClose} className="px-4 py-2 text-sm text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">Annuler</button>
            <button onClick={handleSave} disabled={!draftValid}
              className="px-4 py-2 text-sm font-medium bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors disabled:opacity-40 disabled:cursor-not-allowed">
              Enregistrer
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * src/hooks/usePriceScan.test.ts
 */
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { renderHook, act } from '@testing-library/react';
import { usePriceScan, buildIdleMatrix } from './usePriceScan';
import type { Material } from '@/types/material';
import type { SupplierPrice } from '@/types/price';

// ── Mock adapters ─────────────────────────────────────────────────────────────

const mockGetPrice = vi.fn();

vi.mock('@/adapters/materielelectrique', () => ({
  MaterielElectriqueAdapter: vi.fn().mockImplementation(() => ({ getPrice: mockGetPrice })),
  DEFAULT_SCRAPING_CONFIG: { delayBetweenRequestsMs: 0, requestTimeoutMs: 5000, userAgent: 'test' },
}));

vi.mock('@/adapters/rexel', () => ({
  RexelAdapter: vi.fn().mockImplementation(() => ({ getPrice: vi.fn().mockResolvedValue(null) })),
}));

// ── Fixtures ──────────────────────────────────────────────────────────────────

const MATERIAL_WITH_REF: Material = {
  id: 'mat-1',
  nom: 'Test Material',
  marque: 'Brand',
  categorie: 'Cat',
  references_fournisseurs: { materielelectrique: 'REF-001' },
};

const MATERIAL_NO_REF: Material = {
  id: 'mat-2',
  nom: 'No ref material',
  marque: 'Brand',
  categorie: 'Cat',
  references_fournisseurs: { materielelectrique: null },
};

const MATERIAL_B: Material = {
  id: 'mat-b',
  nom: 'Material B',
  marque: 'Brand',
  categorie: 'Cat',
  references_fournisseurs: { materielelectrique: 'REF-B' },
};

const MOCK_PRICE: SupplierPrice = {
  prix_ht: 18.64,
  stock: 1,
  unite: 'pièce',
  fetchedAt: new Date().toISOString(), // fresh — now
};

const STALE_PRICE: SupplierPrice = {
  prix_ht: 10.0,
  stock: 1,
  unite: 'pièce',
  fetchedAt: new Date(Date.now() - 25 * 60 * 60 * 1000).toISOString(), // 25h ago → stale
};

// ── buildIdleMatrix ───────────────────────────────────────────────────────────

describe('buildIdleMatrix', () => {
  it('creates an idle cell for each material and supplier', () => {
    const matrix = buildIdleMatrix([MATERIAL_WITH_REF, MATERIAL_NO_REF]);
    expect(matrix['mat-1']['materielelectrique'].status).toBe('idle');
    expect(matrix['mat-2']['materielelectrique'].status).toBe('idle');
  });

  it('returns empty object for empty material list', () => {
    expect(buildIdleMatrix([])).toEqual({});
  });
});

// ── usePriceScan ──────────────────────────────────────────────────────────────

describe('usePriceScan', () => {
  beforeEach(() => { vi.clearAllMocks(); });

  it('starts with empty prices and scanning=false', () => {
    const { result } = renderHook(() => usePriceScan());
    expect(result.current.scanning).toBe(false);
    expect(result.current.prices).toEqual({});
  });

  it('sets cells to success after a successful scan', async () => {
    mockGetPrice.mockResolvedValue(MOCK_PRICE);
    const { result } = renderHook(() => usePriceScan());

    await act(async () => { await result.current.startScan([MATERIAL_WITH_REF]); });

    expect(result.current.scanning).toBe(false);
    expect(result.current.prices['mat-1']['materielelectrique'].status).toBe('success');
    expect(result.current.prices['mat-1']['materielelectrique'].data?.prix_ht).toBe(18.64);
  });

  it('sets cell to error when adapter throws', async () => {
    mockGetPrice.mockRejectedValue(new Error('Network fail'));
    const { result } = renderHook(() => usePriceScan());

    await act(async () => { await result.current.startScan([MATERIAL_WITH_REF]); });

    const cell = result.current.prices['mat-1']['materielelectrique'];
    expect(cell.status).toBe('error');
    expect(cell.errorMessage).toBe('Network fail');
  });

  it('sets cell to error when reference is null', async () => {
    const { result } = renderHook(() => usePriceScan());

    await act(async () => { await result.current.startScan([MATERIAL_NO_REF]); });

    const cell = result.current.prices['mat-2']['materielelectrique'];
    expect(cell.status).toBe('error');
    expect(cell.errorMessage).toBe('Référence non renseignée');
  });

  it('does not start a second scan while one is running', async () => {
    let resolveFirst!: () => void;
    mockGetPrice.mockReturnValue(
      new Promise<SupplierPrice>((resolve) => { resolveFirst = () => resolve(MOCK_PRICE); })
    );

    const { result } = renderHook(() => usePriceScan());

    act(() => { void result.current.startScan([MATERIAL_WITH_REF]); });
    await act(async () => { await result.current.startScan([MATERIAL_WITH_REF]); });

    // Only one getPrice call should have been made
    expect(mockGetPrice).toHaveBeenCalledTimes(1);
    await act(async () => { resolveFirst(); });
  });

  it('only fetches the selected materials when selectedIds is provided', async () => {
    mockGetPrice.mockResolvedValue(MOCK_PRICE);
    const { result } = renderHook(() => usePriceScan());

    // Only select mat-1, pass both materials
    await act(async () => {
      await result.current.startScan(
        [MATERIAL_WITH_REF, MATERIAL_B],
        '',
        new Set(['mat-1'])
      );
    });

    // mat-1 should be fetched
    expect(result.current.prices['mat-1']['materielelectrique'].status).toBe('success');
    // mat-b should NOT have been touched (no entry initialised)
    expect(result.current.prices['mat-b']?.['materielelectrique']?.status).toBeUndefined();
    expect(mockGetPrice).toHaveBeenCalledTimes(1);
  });

  it('skips fetching when a cell has a fresh price (< 24h)', async () => {
    mockGetPrice.mockResolvedValue(MOCK_PRICE);
    const { result } = renderHook(() => usePriceScan());

    // First scan — populates with a fresh price
    await act(async () => { await result.current.startScan([MATERIAL_WITH_REF]); });
    expect(mockGetPrice).toHaveBeenCalledTimes(1);

    // Second scan immediately after — price is still fresh, should be skipped
    mockGetPrice.mockClear();
    await act(async () => { await result.current.startScan([MATERIAL_WITH_REF]); });
    expect(mockGetPrice).toHaveBeenCalledTimes(0);
  });

  it('re-fetches when the cached price is stale (> 24h)', async () => {
    // First scan stores a fresh price
    mockGetPrice.mockResolvedValue(MOCK_PRICE);
    const { result } = renderHook(() => usePriceScan());
    await act(async () => { await result.current.startScan([MATERIAL_WITH_REF]); });
    expect(mockGetPrice).toHaveBeenCalledTimes(1);

    // Confirm second scan (fresh) is skipped
    mockGetPrice.mockClear();
    await act(async () => { await result.current.startScan([MATERIAL_WITH_REF]); });
    expect(mockGetPrice).toHaveBeenCalledTimes(0);

    // Fast-forward time by 25 h so the cached price becomes stale
    const realNow = Date.now;
    vi.spyOn(Date, 'now').mockReturnValue(realNow() + 25 * 60 * 60 * 1000);

    try {
      mockGetPrice.mockClear();
      mockGetPrice.mockResolvedValue({ ...MOCK_PRICE, fetchedAt: new Date().toISOString() });
      await act(async () => { await result.current.startScan([MATERIAL_WITH_REF]); });
      expect(mockGetPrice).toHaveBeenCalledTimes(1);
    } finally {
      vi.spyOn(Date, 'now').mockRestore();
    }
  });
});

